const idea = $input.first().json;

const systemPrompt = `You are an SEO writer for perfect1.co.il, an Israeli business portal focused on עוסק פטור, עוסק מורשה, חברה בע"מ, מיסוי, and guides for self-employed in Israel.

You must output a COMPLETE valid JSON article file (Hebrew, RTL) matching this exact schema:

{
  "slug": "kebab-case-slug",
  "category": "one of: misui, maam, miktzoa, osek-patur, osek-murshe, hevra-bam, sgirat-tikim, guides",
  "metaTitle": "SEO title up to 60 chars ending with | פרפקט וואן",
  "metaDescription": "155 chars max with CTA",
  "keywords": ["5-8 Hebrew keywords"],
  "heroTitle": "strong Hebrew H1",
  "heroSubtitle": "1-2 sentences explaining the article value",
  "publishDate": "2026-04-16",
  "updatedDate": "2026-04-16",
  "author": {"name": "צוות פרפקט וואן", "role": "מומחי מיסוי ועסקים"},
  "readTime": 10,
  "toc": [{"id": "...", "title": "..."}],
  "sections": [
    {
      "id": "intro",
      "type": "text",
      "title": "...",
      "answerBlock": "1-2 sentences direct answer for AI citation",
      "content": "paragraph with [internal links](/category/slug) in markdown"
    },
    {"id": "list-section", "type": "list", "title": "...", "description": "...", "items": [{"title": "...", "description": "..."}]},
    {"id": "steps", "type": "steps", "title": "...", "answerBlock": "...", "steps": [{"number": 1, "title": "...", "description": "..."}]},
    {"id": "callout", "type": "callout", "variant": "tip", "title": "...", "content": "..."},
    {"id": "faq", "type": "faq", "title": "שאלות נפוצות", "items": [{"question": "...", "answer": "..."}]}
  ],
  "relatedArticles": [{"category": "...", "slug": "...", "title": "..."}]
}

Rules:
- 1500-2500 words total
- 8-12 sections
- 6-10 FAQ questions
- answerBlock on every major text section (for AEO)
- At least 4 internal links to existing articles
- All Hebrew, RTL
- Year 2026 facts only
- Commercial intent where applicable (CTA in middle)
- Return ONLY the JSON, no markdown fences, no explanation`;

const userPrompt = `Write a comprehensive article for:

Target query: ${idea.target_query}
Title: ${idea.suggested_article_title}
Search intent: ${idea.search_intent}
Angle: ${idea.suggested_angle}
Why it matters: ${idea.why_it_matters}
Parent page: ${idea.parent_page_url}

Related internal links to use: ${JSON.stringify(idea.internal_links_json || [])}

Return only a valid JSON matching the schema.`;

return [{
  json: {
    idea_id: idea.id,
    target_query: idea.target_query,
    suggested_title: idea.suggested_article_title,
    parent_page: idea.parent_page_url,
    messages: [
      { role: 'system', content: systemPrompt },
      { role: 'user', content: userPrompt }
    ]
  }
}];

const openaiResp = $input.first().json;
const promptCtx = $('Build Article Prompt').first().json;

let article;
try {
  const text = openaiResp.choices[0].message.content;
  article = JSON.parse(text);
} catch (e) {
  return [{ json: { error: 'parse_failed', message: e.message, idea_id: promptCtx.idea_id } }];
}

if (!article.slug || !article.category || !article.sections) {
  return [{ json: { error: 'missing_fields', idea_id: promptCtx.idea_id } }];
}

const today = new Date().toISOString().split('T')[0];
article.publishDate = today;
article.updatedDate = today;

const wordCount = JSON.stringify(article).split(/\s+/).length;

const filePath = `src/content/${article.category}/${article.slug}.json`;
const fileContent = JSON.stringify(article, null, 2);

return [{
  json: {
    idea_id: promptCtx.idea_id,
    category: article.category,
    slug: article.slug,
    title: article.heroTitle || article.metaTitle,
    file_path: filePath,
    file_content: fileContent,
    file_content_b64: Buffer.from(fileContent, 'utf-8').toString('base64'),
    commit_message: `Feat: Auto-published article — ${article.heroTitle || article.slug}\n\nAuto-generated by SEO Content Pipeline from idea ${promptCtx.idea_id}`,
    word_count: wordCount
  }
}];

